int leastInterval(vector<char>& tasks, int n) {
    unordered_map<char, int> counts;
    for (char c : tasks) counts[c]++;
    priority_queue<int> pq;
    for (auto p : counts) pq.push(p.second);
    queue<pair<int, int>> q; // {count, available_time}
    int time = 0;
    while (!pq.empty() || !q.empty()) {
        time++;
        if (!pq.empty()) {
            int cnt = pq.top() - 1; pq.pop();
            if (cnt > 0) q.push({cnt, time + n});
        }
        if (!q.empty() && q.front().second == time) {
            pq.push(q.front().first);
            q.pop();
        }
    }
    return time;
}

int shortestSubarray(vector<int>& nums, int k) {
    int n = nums.size();
    vector<long long> pref(n + 1, 0);
    for (int i = 0; i < n; ++i) pref[i+1] = pref[i] + nums[i];
    deque<int> q;
    int res = INT_MAX;
    for (int i = 0; i <= n; ++i) {
        while (!q.empty() && pref[i] - pref[q.front()] >= k) {
            res = min(res, i - q.front());
            q.pop_front();
        }
        while (!q.empty() && pref[i] <= pref[q.back()]) {
            q.pop_back();
        }
        q.push_back(i);
    }
    return res == INT_MAX ? -1 : res;
}

