from collections import deque
def findMaxValueOfEquation(points: list[list[int]], k: int) -> int:
    q = deque() # stores (y - x, x)
    res = float('-inf')
    for x, y in points:
        while q and x - q[0][1] > k:
            q.popleft()
        if q:
            res = max(res, y + x + q[0][0])
        while q and q[-1][0] <= y - x:
            q.pop()
        q.append((y - x, x))
    return res

