int findMaxValueOfEquation(vector<vector<int>>& points, int k) {
    deque<pair<int, int>> q; // {y - x, x}
    int res = INT_MIN;
    for (auto& p : points) {
        int x = p[0], y = p[1];
        while (!q.empty() && x - q.front().second > k) {
            q.pop_front();
        }
        if (!q.empty()) {
            res = max(res, y + x + q.front().first);
        }
        while (!q.empty() && q.back().first <= y - x) {
            q.pop_back();
        }
        q.push_back({y - x, x});
    }
    return res;
}

