from collections import deque
def maxSlidingWindow(nums, k):
    res = []
    q = deque() # Stores indices of elements

    for i, num in enumerate(nums):
        # 1. Maintain monotonic decreasing queue
        while q and nums[q[-1]] <= num:
            q.pop()
        q.append(i)

        # 2. Evict indices outside current window bounds
        if q[0] < i - k + 1:
            q.popleft()

        # 3. Add max element to results once window is established
        if i >= k - 1:
            res.append(nums[q[0]])
    return res

cppCode:
vector<int> maxSlidingWindow(vector<int>& nums, int k) {
    vector<int> res;
    deque<int> q; // Stores indices
    for (int i = 0; i < nums.size(); ++i) {
        while (!q.empty() && nums[q.back()] <= nums[i]) {
            q.pop_back();
        }
        q.push_back(i);

        if (q.front() < i - k + 1) {
            q.pop_front();
        }
        if (i >= k - 1) {
            res.push_back(nums[q.front()]);
        }
    }
    return res;
}
